from collections import Counter

def isNStraightHand(hand, groupSize):
    if len(hand) % groupSize != 0:
        return False
    count = Counter(hand)
    for card in sorted(count):
        c = count[card]
        if c > 0:
            for k in range(groupSize):
                if count[card + k] < c:
                    return False
                count[card + k] -= c
    return True

def mergeTriplets(triplets, target):
