def checkValidString(s):
    min_open = max_open = 0
    for c in s:
        if c == '(':
            min_open += 1
            max_open += 1
        elif c == ')':
            min_open -= 1
            max_open -= 1
        else:  # '*'
            min_open -= 1  # treat as ')'
            max_open += 1  # treat as '('
        if max_open < 0:
            return False
        if min_open < 0:
            min_open = 0  # invalid '-' interpretations clamped
    return min_open == 0

